import { useEffect, useRef, useState } from 'react';
import * as THREE from 'three';

const DEFAULT_WS_URL = 'ws://localhost:8000/ws';

export default function CoreVisualizer() {
  const mountRef = useRef<HTMLDivElement>(null);
  const [phase, setPhase] = useState('Idle');

  useEffect(() => {
    const wsUrl = process.env.NEXT_PUBLIC_WS_URL ?? DEFAULT_WS_URL;
    const ws = new WebSocket(wsUrl);

    ws.onmessage = (e) => {
      const data = JSON.parse(e.data);
      setPhase(data.phase);
    };

    ws.onerror = () => {
      setPhase('ConnectionError');
    };

    const scene = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(75, 1, 0.1, 1000);
    const renderer = new THREE.WebGLRenderer({ antialias: true });
    renderer.setSize(400, 400);
    mountRef.current?.appendChild(renderer.domElement);

    const geometry = new THREE.SphereGeometry(1, 64, 64);
    const material = new THREE.MeshStandardMaterial({
      color: 0x4fd1c5,
      emissive: 0x1a1a40,
      emissiveIntensity: 0.6,
      metalness: 0.3,
      roughness: 0.4,
    });

    const sphere = new THREE.Mesh(geometry, material);
    scene.add(sphere);

    const light = new THREE.PointLight(0x4fd1c5, 2, 10);
    scene.add(light);
    camera.position.z = 3;

    let animationId = 0;

    const animate = () => {
      animationId = requestAnimationFrame(animate);
      sphere.rotation.y += 0.01;
      material.emissiveIntensity = 0.5 + Math.sin(Date.now() * 0.002) * 0.4;
      renderer.render(scene, camera);
    };

    animate();

    return () => {
      cancelAnimationFrame(animationId);
      ws.close();
      geometry.dispose();
      material.dispose();
      renderer.dispose();
      if (mountRef.current?.contains(renderer.domElement)) {
        mountRef.current.removeChild(renderer.domElement);
      }
    };
  }, []);

  return (
    <div style={{ textAlign: 'center' }}>
      <h2 style={{ color: '#4fd1c5' }}>{phase}</h2>
      <div ref={mountRef} />
    </div>
  );
}
